def login_redirect(next_url: str = None, default_url: str = "/", host_url: str = "http://localhost") -> str:
    if next_url and is_safe_redirect_url(next_url, host_url):
        return urljoin(host_url, next_url)
    return urljoin(host_url, default_url)


